  extern virtual function bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] get_spi_multilane_max_address_frame(bit [1:0] transfer_mode, int address_frame_size);

  //----------------------------------------------------------------------------
  /**
   * This method returns the minimum parallel mode value for the current flash command.
   */ 
  extern virtual function int get_spi_flash_min_parallel_mode(input svt_spi_types::flash_command_enum flash_command);
  
  //----------------------------------------------------------------------------
  /**
   * This method returns the maximum parallel mode value for the current flash command.
   */ 
  extern virtual function int get_spi_flash_max_parallel_mode(input svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method returns the Chip Physical Address. Required in Multi-Chip Mode
   */ 
  extern virtual function int get_chip_phy_address(bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] addr_fr,svt_spi_types::flash_command_type_enum flash_cmd_type);
  
  //----------------------------------------------------------------------------
  /**
   * This method returns the minimum JEDEC HW Reset CS Low Time.
   */ 
  extern virtual function int get_spi_flash_min_jedec_hw_reset_cs_low_time();
  
  //----------------------------------------------------------------------------
  /**
   * This method returns the maximum JEDEC HW Reset CS Low Time.
   */ 
  extern virtual function int get_spi_flash_max_jedec_hw_reset_cs_low_time();
  
  //----------------------------------------------------------------------------
  /** This method return whether the command is FAST_READ type/XIP type or not*/
  extern virtual function bit whether_spi_flash_fast_read_or_xip_command(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode);

  //----------------------------------------------------------------------------
  /** 
   * This method return whether current flash command supports Data Bytes on 16 lanes. <br/>
   * Ex: in APMEMORY device family "APS_OBR" parts only Memory Read/Write Commands are valid for this feature
   */
  extern virtual function bit whether_spi_flash_x16_data_lane_is_applicable(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  // This method returns valid data_frame_size for selected flash command type
  extern virtual function int constrant_solve_get_spi_flash_max_data_frame_size(svt_spi_types::flash_command_type_enum flash_command_type,int data_frame_size);

  // ---------------------------------------------------------------------------
`ifdef SVT_VMM_TECHNOLOGY
  `vmm_typename(svt_spi_transaction)
  `vmm_class_factory(svt_spi_transaction)
`endif

  // ---------------------------------------------------------------------------
endclass

